  function rowCity(row) { return row.ciudad || row.ciutat || ""; }
  function setRowCity(row, value) { if ("ciutat" in row && !("ciudad" in row)) row.ciutat = value; else row.ciudad = value; }
  function rowsWithLineNumbers(text) { return indexedRows(text).map(function(x,i){x._line=i+2;return x;}).filter(hasImportMarkData); }
  function invalidCityRows(rows) { return rows.filter(function(row){return !selectedCity(rowCity(row));}); }
