  async function beginMultiMarksImport(text) { pendingMultiMarks=rowsWithLineNumbers(text).filter(function(x){return String(x.atleta||"").trim()!=="";});if(!pendingMultiMarks.length){status("multi-mark-import-status","El fichero no contiene la columna Atleta o no tiene filas.",true);return;}if(invalidCityRows(pendingMultiMarks).length){renderCityReview("multi-mark-import-review-form","multi-mark-import-review-body",pendingMultiMarks);status("multi-mark-import-status","Revisa las ciudades no encontradas antes de importar.",false);return;}await continueMultiMarksImport(); }
