  byId("replace-marks-form").addEventListener("submit",function(e){e.preventDefault();var payload={field:byId("replace-field").value,search:byId("replace-search").value,replace:byId("replace-value").value,area:byId("replace-area").value,year:byId("replace-year").value};if(payload.field==="city"){var source=selectedCity(payload.search), target=selectedCity(payload.replace);if(!source||!target){status("replace-marks-status","Selecciona la ciudad a reemplazar y la ciudad nueva del listado.",true);return;}payload.searchCityId=source.id;payload.replaceCityId=target.id;}else{var filterCityValue=byId("replace-city").value.trim();if(filterCityValue){var filterCity=selectedCity(filterCityValue);if(!filterCity){status("replace-marks-status","Selecciona una ciudad existente para filtrar.",true);return;}payload.cityId=filterCity.id;}}request("/marks/replace",{method:"POST",body:JSON.stringify(payload)}).then(async function(out){await refresh();status("replace-marks-status",out.updated+" marcas actualizadas.",false);}).catch(function(error){status("replace-marks-status",error.message,true);});});
